package federation

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/http/httptest"
	"strings"
	"sync"
	"sync/atomic"
	"testing"
	"time"
)

// graphQLBody is a minimal JSON object suitable for asserting against in tests.
func okGraphQLBody(t *testing.T, payload any) []byte {
	t.Helper()
	b, err := json.Marshal(payload)
	if err != nil {
		t.Fatalf("marshal: %v", err)
	}
	return b
}

// newSpokeServer returns an httptest.Server that responds to /graphql with the
// given handler and exposes its base URL.
func newSpokeServer(t *testing.T, handler http.HandlerFunc) (*httptest.Server, SpokeRecord) {
	t.Helper()
	mux := http.NewServeMux()
	mux.HandleFunc("/graphql", handler)
	srv := httptest.NewServer(mux)
	t.Cleanup(srv.Close)
	return srv, SpokeRecord{
		NodeID:        "node-" + srv.Listener.Addr().String(),
		Name:          "spoke",
		URL:           srv.URL,
		DDxVersion:    "0.1.0",
		SchemaVersion: CurrentSchemaVersion,
		Status:        StatusActive,
	}
}

func TestFanOut_AllSpokesSucceed(t *testing.T) {
	_, s1 := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": map[string]any{"node": "1"}}))
	})
	_, s2 := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": map[string]any{"node": "2"}}))
	})

	c := NewFanOutClient()
	c.HubDDxVersion = "0.1.0"
	c.HubSchemaVersion = CurrentSchemaVersion

	res, err := c.Execute(context.Background(), []SpokeRecord{s1, s2}, &FanOutRequest{Query: "{ __typename }"})
	if err != nil {
		t.Fatalf("execute: %v", err)
	}
	if len(res.Responses) != 2 {
		t.Fatalf("want 2 responses, got %d (errors=%v)", len(res.Responses), res.Errors)
	}
	if len(res.Errors) != 0 {
		t.Fatalf("want 0 errors, got %v", res.Errors)
	}
}

func TestFanOut_PartialResultOnOneFailure(t *testing.T) {
	_, good := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
	})
	dead := SpokeRecord{
		NodeID:        "dead-spoke",
		Name:          "dead",
		URL:           "http://127.0.0.1:1", // port 1 → connection refused
		DDxVersion:    "0.1.0",
		SchemaVersion: CurrentSchemaVersion,
		Status:        StatusActive,
	}
	c := NewFanOutClient()
	c.HubDDxVersion = "0.1.0"
	c.HubSchemaVersion = CurrentSchemaVersion
	c.PerNodeTimeout = 500 * time.Millisecond

	res, err := c.Execute(context.Background(), []SpokeRecord{good, dead}, &FanOutRequest{Query: "{ __typename }"})
	if err != nil {
		t.Fatalf("execute: %v", err)
	}
	if _, ok := res.Responses[good.NodeID]; !ok {
		t.Fatalf("expected good spoke to succeed, got %+v", res)
	}
	if _, ok := res.Errors[dead.NodeID]; !ok {
		t.Fatalf("expected dead spoke to be in errors map, got %+v", res.Errors)
	}
	if status, ok := res.StatusUpdates[dead.NodeID]; !ok || status != StatusOffline {
		t.Fatalf("expected dead spoke status update offline, got %+v", res.StatusUpdates)
	}
	// The good spoke must NOT receive a status update — only transport failures do.
	if _, ok := res.StatusUpdates[good.NodeID]; ok {
		t.Fatalf("good spoke should not receive a status update")
	}
}

func TestFanOut_PerNodeTimeoutDoesNotBlockOthers(t *testing.T) {
	_, fast := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "fast"}))
	})
	_, slow := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		select {
		case <-time.After(2 * time.Second):
		case <-r.Context().Done():
		}
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "slow"}))
	})

	c := NewFanOutClient()
	c.HubDDxVersion = "0.1.0"
	c.HubSchemaVersion = CurrentSchemaVersion
	c.PerNodeTimeout = 100 * time.Millisecond

	start := time.Now()
	res, err := c.Execute(context.Background(), []SpokeRecord{slow, fast}, &FanOutRequest{Query: "{ __typename }"})
	elapsed := time.Since(start)
	if err != nil {
		t.Fatalf("execute: %v", err)
	}
	// Should complete in well under the slow spoke's 2s wait.
	if elapsed > 1500*time.Millisecond {
		t.Fatalf("fan-out took %s — slow spoke blocked others", elapsed)
	}
	if _, ok := res.Responses[fast.NodeID]; !ok {
		t.Fatalf("fast spoke missing from responses: %+v", res)
	}
	if _, ok := res.Errors[slow.NodeID]; !ok {
		t.Fatalf("slow spoke missing from errors: %+v", res.Errors)
	}
	// Per-node timeout must not flip the spoke to offline (could just be stale).
	if _, ok := res.StatusUpdates[slow.NodeID]; ok {
		t.Fatalf("per-node timeout must not produce a status update; got %+v", res.StatusUpdates)
	}
	// The per-node detail should classify the slow spoke as OutcomeTimeout.
	var found bool
	for _, n := range res.Nodes {
		if n.NodeID == slow.NodeID {
			if n.Outcome != OutcomeTimeout {
				t.Fatalf("slow spoke outcome = %q, want %q", n.Outcome, OutcomeTimeout)
			}
			found = true
		}
	}
	if !found {
		t.Fatalf("slow spoke not present in Nodes")
	}
}

func TestFanOut_MaxConcurrencyEnforced(t *testing.T) {
	const totalSpokes = 10
	const maxConc = 3

	var inFlight int32
	var peak int32
	gate := make(chan struct{})

	handler := func(w http.ResponseWriter, r *http.Request) {
		cur := atomic.AddInt32(&inFlight, 1)
		for {
			p := atomic.LoadInt32(&peak)
			if cur <= p || atomic.CompareAndSwapInt32(&peak, p, cur) {
				break
			}
		}
		<-gate
		atomic.AddInt32(&inFlight, -1)
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
	}

	var spokes []SpokeRecord
	for i := 0; i < totalSpokes; i++ {
		_, s := newSpokeServer(t, handler)
		s.NodeID = fmt.Sprintf("node-%d", i)
		spokes = append(spokes, s)
	}

	c := NewFanOutClient()
	c.HubDDxVersion = "0.1.0"
	c.HubSchemaVersion = CurrentSchemaVersion
	c.MaxConcurrency = maxConc
	c.PerNodeTimeout = 5 * time.Second

	done := make(chan *FanOutResult, 1)
	go func() {
		res, _ := c.Execute(context.Background(), spokes, &FanOutRequest{Query: "{ __typename }"})
		done <- res
	}()

	// Give all goroutines time to spin up and observe peak concurrency.
	deadline := time.Now().Add(2 * time.Second)
	for time.Now().Before(deadline) {
		if atomic.LoadInt32(&peak) >= int32(maxConc) {
			break
		}
		time.Sleep(10 * time.Millisecond)
	}
	// Briefly observe steady-state peak before releasing.
	time.Sleep(50 * time.Millisecond)
	if got := atomic.LoadInt32(&peak); got > int32(maxConc) {
		t.Fatalf("peak in-flight %d exceeded max-concurrency %d", got, maxConc)
	}
	close(gate)

	res := <-done
	if len(res.Responses) != totalSpokes {
		t.Fatalf("want %d successes, got %d", totalSpokes, len(res.Responses))
	}
	if got := atomic.LoadInt32(&peak); got > int32(maxConc) {
		t.Fatalf("peak in-flight %d exceeded max-concurrency %d", got, maxConc)
	}
	if got := atomic.LoadInt32(&peak); got == 0 {
		t.Fatalf("peak in-flight is zero — handler never observed concurrency")
	}
}

func TestFanOut_VersionIncompatibleSpokesSkipped(t *testing.T) {
	var hits int32
	_, compat := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		atomic.AddInt32(&hits, 1)
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
	})
	_, incompat := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		atomic.AddInt32(&hits, 1)
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
	})
	incompat.NodeID = "incompat-spoke"
	incompat.DDxVersion = "9.0.0" // major mismatch

	var logs []string
	var logMu sync.Mutex
	c := NewFanOutClient()
	c.HubDDxVersion = "0.1.0"
	c.HubSchemaVersion = CurrentSchemaVersion
	c.Logger = func(format string, args ...any) {
		logMu.Lock()
		logs = append(logs, fmt.Sprintf(format, args...))
		logMu.Unlock()
	}

	res, err := c.Execute(context.Background(), []SpokeRecord{compat, incompat}, &FanOutRequest{Query: "{ __typename }"})
	if err != nil {
		t.Fatalf("execute: %v", err)
	}
	if got := atomic.LoadInt32(&hits); got != 1 {
		t.Fatalf("expected exactly one HTTP hit (compat only); got %d", got)
	}
	reason, ok := res.Skipped[incompat.NodeID]
	if !ok || reason != SkipReasonIncompatibleVersion {
		t.Fatalf("expected incompat spoke to be skipped with %q, got %+v", SkipReasonIncompatibleVersion, res.Skipped)
	}

package server

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// hubFromServer wires the hub-mode Server into a real httptest.Server so the
// spoke under test can hit it over HTTP. The returned closer must be called.
//
// All requests against the returned URL will appear to originate from
// 127.0.0.1, so the hub's strict default trust gate accepts them — exactly
// what we want for the lifecycle integration tests.
func hubFromServer(t *testing.T, srv *Server) (string, func()) {
	t.Helper()
	httpSrv := httptest.NewServer(srv.Handler())
	t.Cleanup(httpSrv.Close)
	return httpSrv.URL, httpSrv.Close
}

// spokeStatePath is the conventional per-test spoke-state location under
// XDG_DATA_HOME (which setupTestDir already isolates).
func spokeStatePath(t *testing.T) string {
	t.Helper()
	dir := t.TempDir()
	return filepath.Join(dir, "spoke-state.json")
}

func WithSpokeHeartbeatInterval(d time.Duration) SpokeOption {
	return func(c *federation.SpokeConfig) { c.HeartbeatInterval = d }
}

func WithSpokeHeartbeatJitter(j float64) SpokeOption {
	return func(c *federation.SpokeConfig) { c.HeartbeatJitterFraction = j }
}

func WithSpokeStatePath(p string) SpokeOption {
	return func(c *federation.SpokeConfig) { c.StatePath = p }
}

func WithSpokeHTTPClient(client *http.Client) SpokeOption {
	return func(c *federation.SpokeConfig) { c.HTTPClient = client }
}

func WithSpokeSelfURL(url string) SpokeOption {
	return func(c *federation.SpokeConfig) { c.URL = url }
}

func WithSpokeNodeID(id string) SpokeOption {
	return func(c *federation.SpokeConfig) { c.NodeID = id }
}

// AC: --hub-address flag registers on startup. Spoke appears in hub registry.
func TestSpokeRegistersOnStart(t *testing.T) {
	hub := newHubServer(t, false)
	hubURL, _ := hubFromServer(t, hub)

	dir := setupTestDir(t)
	spoke := New(":0", dir)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	if err := spoke.EnableSpokeMode(ctx, hubURL, "https://spoke-self:9000",
		WithSpokeStatePath(spokeStatePath(t)),
		WithSpokeHeartbeatInterval(time.Hour), // disable heartbeat noise
		WithSpokeNodeID("spoke-1"),
	); err != nil {
		t.Fatalf("EnableSpokeMode: %v", err)
	}

	snap := hub.HubFederationRegistrySnapshot()
	if len(snap.Spokes) != 1 {
		t.Fatalf("hub should hold 1 spoke after register, got %d", len(snap.Spokes))
	}
	if snap.Spokes[0].NodeID != "spoke-1" {
		t.Errorf("hub registered wrong node_id: %q", snap.Spokes[0].NodeID)
	}
	if snap.Spokes[0].URL != "https://spoke-self:9000" {
		t.Errorf("hub registered wrong URL: %q", snap.Spokes[0].URL)
	}
	if !spoke.SpokeMode {
		t.Errorf("Server.SpokeMode should be true after EnableSpokeMode")
	}
}

// AC: Re-start with same node_id is idempotent (replaces, not duplicates).
func TestSpokeLifecycle_Register_Idempotent(t *testing.T) {
	hub := newHubServer(t, false)
	hubURL, _ := hubFromServer(t, hub)
	statePath := spokeStatePath(t)
	dir := setupTestDir(t)

	for i := 0; i < 3; i++ {
		s := New(":0", dir)
		ctx, cancel := context.WithCancel(context.Background())
		if err := s.EnableSpokeMode(ctx, hubURL, "https://spoke-self:9000",
			WithSpokeStatePath(statePath),
			WithSpokeHeartbeatInterval(time.Hour),
			WithSpokeNodeID("spoke-x"),
		); err != nil {
			t.Fatalf("iteration %d: EnableSpokeMode: %v", i, err)
		}
		_ = s.ShutdownSpoke(ctx)
		cancel()
	}

	snap := hub.HubFederationRegistrySnapshot()
	if len(snap.Spokes) > 1 {
		t.Errorf("idempotent re-registration produced %d spokes; want ≤1", len(snap.Spokes))
	}
}

// AC: URL change between restarts triggers re-registration with new URL.
func TestSpokeLifecycle_URLChange_Triggers_Reregister(t *testing.T) {
	hub := newHubServer(t, false)
	hubURL, _ := hubFromServer(t, hub)
	statePath := spokeStatePath(t)
	dir := setupTestDir(t)

	s1 := New(":0", dir)
	ctx1, cancel1 := context.WithCancel(context.Background())
	if err := s1.EnableSpokeMode(ctx1, hubURL, "https://spoke-old:9000",
		WithSpokeStatePath(statePath),
		WithSpokeHeartbeatInterval(time.Hour),
		WithSpokeNodeID("spoke-roving"),
	); err != nil {
		t.Fatalf("first start: %v", err)
	}
	cancel1()

	// Restart with a new URL.
	s2 := New(":0", dir)
	ctx2, cancel2 := context.WithCancel(context.Background())
	defer cancel2()
	if err := s2.EnableSpokeMode(ctx2, hubURL, "https://spoke-new:9000",
		WithSpokeStatePath(statePath),
		WithSpokeHeartbeatInterval(time.Hour),
		WithSpokeNodeID("spoke-roving"),
	); err != nil {
		t.Fatalf("second start: %v", err)
	}

	if !s2.SpokeAgent().URLChanged() {
		t.Errorf("expected URLChanged=true after url change between restarts")
	}
	if got := s2.SpokeAgent().PreviousURL(); got != "https://spoke-old:9000" {
		t.Errorf("PreviousURL: want old URL, got %q", got)
	}

	snap := hub.HubFederationRegistrySnapshot()
	if len(snap.Spokes) != 1 {
		t.Fatalf("want 1 spoke after URL change, got %d", len(snap.Spokes))
	}
	if snap.Spokes[0].URL != "https://spoke-new:9000" {
		t.Errorf("hub did not pick up new URL: got %q", snap.Spokes[0].URL)
	}
}

// AC: Heartbeat interval 30s ± jitter. We can't directly assert the
// wall-clock 30s cadence, but we can verify the default delay stays within
// the ADR-007 [25s, 35s] window and that the delay is actually jittered.
func TestSpokeLifecycle_Heartbeat_30sJitter(t *testing.T) {
	if got := federation.DefaultHeartbeatInterval; got != 30*time.Second {
		t.Errorf("DefaultHeartbeatInterval drift: %v want 30s", got)
	}
	cfg := federation.SpokeConfig{
		NodeID:            "n1",
		URL:               "https://x",
		HubURL:            "https://hub",
		HeartbeatInterval: federation.DefaultHeartbeatInterval,
		StatePath:         filepath.Join(t.TempDir(), "spoke.json"),
	}
	sp, err := federation.NewSpoke(cfg)
	if err != nil {
		t.Fatalf("NewSpoke: %v", err)
	}
	// Sample many delays — none should fall outside the 30s ± 5s window.
	low := 25 * time.Second
	high := 35 * time.Second
	sawJitter := false
	for i := 0; i < 200; i++ {
		d := sp.NextHeartbeatDelay()
		if d < low || d > high {
			t.Fatalf("delay %v outside ADR-007 bounds [%v,%v]", d, low, high)
		}
		if d != cfg.HeartbeatInterval {
			sawJitter = true
		}
	}
	if !sawJitter {
		t.Errorf("expected jitter to vary delays; saw constant %v", cfg.HeartbeatInterval)
	}
}

// Heartbeats actually flip status to active end-to-end.
func TestSpokeHeartbeatFlipsStatusActive(t *testing.T) {
	hub := newHubServer(t, false)
	hubURL, _ := hubFromServer(t, hub)
	dir := setupTestDir(t)

	spoke := New(":0", dir)
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	if err := spoke.EnableSpokeMode(ctx, hubURL, "https://spoke:9000",
		WithSpokeStatePath(spokeStatePath(t)),
		WithSpokeHeartbeatInterval(20*time.Millisecond),
		WithSpokeHeartbeatJitter(0.01),
		WithSpokeNodeID("spoke-hb"),
	); err != nil {
		t.Fatalf("EnableSpokeMode: %v", err)
	}

	// Wait for at least one heartbeat to land.
	deadline := time.Now().Add(2 * time.Second)
	for time.Now().Before(deadline) {
		if spoke.SpokeAgent().HeartbeatCount() >= 1 {
			break
		}
		time.Sleep(10 * time.Millisecond)
	}
	if spoke.SpokeAgent().HeartbeatCount() < 1 {
		t.Fatalf("heartbeat never fired; count=%d err=%v",
			spoke.SpokeAgent().HeartbeatCount(), spoke.SpokeAgent().LastHeartbeatError())
	}

	snap := hub.HubFederationRegistrySnapshot()
	if len(snap.Spokes) != 1 {
		t.Fatalf("want 1 spoke, got %d", len(snap.Spokes))
	}
	if snap.Spokes[0].Status != federation.StatusActive {
		t.Errorf("want active after heartbeat, got %q", snap.Spokes[0].Status)
	}
}

// AC: Graceful shutdown sends deregister (best-effort).
func TestSpokeDeregistersOnShutdown(t *testing.T) {
