package server

import (
	"context"
	"fmt"
	"log"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// federationSpoke holds the per-server state for spoke-mode federation: the
// running spoke lifecycle agent and its config (so tests can introspect what
// was advertised to the hub).
type federationSpoke struct {
	agent   *federation.Spoke
	hubURL  string
	selfURL string
}

// EnableSpokeMode launches the spoke-side lifecycle: register-on-start,
// jittered heartbeat, URL-change detection across restarts, and best-effort
// deregister-on-shutdown. Idempotent: a second call is a no-op.
//
// hubURL is the federation hub base URL (e.g. "https://hub:7743").
// selfURL is this server's externally-reachable URL advertised to the hub
// (e.g. "https://node-a:7743"). When empty, a default is constructed from
// the bind address.
//
// The returned error reflects the initial registration outcome — if the hub
// rejects the registration (version mismatch, identity conflict, etc.) the
// spoke does not start.
//
// Both EnableHubMode and EnableSpokeMode may be called on the same server
// (hub_spoke role).
func (s *Server) EnableSpokeMode(ctx context.Context, hubURL, selfURL string, opts ...SpokeOption) error {
	if s.spoke != nil {
		return nil
	}
	if strings.TrimSpace(hubURL) == "" {
		return fmt.Errorf("federation: --hub-address URL required for spoke mode")
	}
	if strings.TrimSpace(selfURL) == "" {
		// Best-effort default: scheme is https + bind address. Operators can
		// override via the explicit selfURL arg.
		selfURL = "https://" + s.Addr
	}

	cfg := federation.SpokeConfig{
		NodeID:        s.state.Node.ID,
		Name:          s.state.Node.Name,
		URL:           selfURL,
		HubURL:        hubURL,
		DDxVersion:    HubDefaultDDxVersion,
		SchemaVersion: federation.CurrentSchemaVersion,
		Logger:        func(format string, args ...any) { log.Printf("WARN: "+format, args...) },
	}
	for _, proj := range s.state.GetProjects() {
		if proj.ID != "" {
			cfg.ProjectIDs = append(cfg.ProjectIDs, proj.ID)
		}
	}
	for _, opt := range opts {
		opt(&cfg)
	}

	agent, err := federation.NewSpoke(cfg)
	if err != nil {
		return err
	}

	if agent.URLChanged() {
		log.Printf("federation: spoke URL changed from %q to %q; will re-register with new URL",
			agent.PreviousURL(), selfURL)
	}

	if err := agent.Start(ctx); err != nil {
		return fmt.Errorf("federation: spoke register: %w", err)
	}

	s.spoke = &federationSpoke{agent: agent, hubURL: hubURL, selfURL: selfURL}
	s.SpokeMode = true
	return nil
}

// SpokeOption customises the SpokeConfig used by EnableSpokeMode.
type SpokeOption func(*federation.SpokeConfig)

// SpokeAgent exposes the underlying federation.Spoke for tests and operator
// introspection. Returns nil if spoke mode is not enabled.
func (s *Server) SpokeAgent() *federation.Spoke {
	if s.spoke == nil {
		return nil
	}
	return s.spoke.agent
}

// ShutdownSpoke stops the spoke lifecycle (heartbeat + best-effort deregister).
// Safe to call when spoke mode is not enabled — returns nil. Called from
// graceful shutdown paths so the hub registry does not show a stale spoke.
func (s *Server) ShutdownSpoke(ctx context.Context) error {
	if s.spoke == nil {
		return nil
	}
	return s.spoke.agent.Shutdown(ctx)
}

package server

import (
	"context"
	"sync"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// hubFederationProvider adapts a *federationHub to the
// ddxgraphql.FederationProvider interface so federationNodes /
// federated{Beads,Runs,Projects} resolvers can read live registry state and
// drive fan-out against registered spokes.
//
// The provider applies StatusUpdates from each fan-out result back to the
// registry on the same lock the hub uses, so subsequent /federation page
// loads (or fan-out queries) observe the propagated transport-level
// status (offline) without an out-of-band reconcile loop.
type hubFederationProvider struct {
	server *Server
	once   sync.Once
	client *federation.FanOutClient
}

func newHubFederationProvider(s *Server) *hubFederationProvider {
	return &hubFederationProvider{server: s}
}

// fanOutClient is lazy-built so tests that swap s.hub mid-run see a fresh
// client wired to the latest hub config.
func (p *hubFederationProvider) fanOutClient() *federation.FanOutClient {
	p.once.Do(func() {
		c := federation.NewFanOutClient()
		c.HubDDxVersion = p.server.hub.hubDDxVersion
		c.HubSchemaVersion = p.server.hub.hubSchemaVer
		p.client = c
	})
	return p.client
}

// Spokes returns a copy of the current registry's spokes.
func (p *hubFederationProvider) Spokes() []federation.SpokeRecord {
	if p.server.hub == nil {
		return nil
	}
	p.server.hub.mu.Lock()
	defer p.server.hub.mu.Unlock()
	out := make([]federation.SpokeRecord, len(p.server.hub.registry.Spokes))
	copy(out, p.server.hub.registry.Spokes)
	return out
}

// FanOut runs req against every registered spoke and applies any returned
// StatusUpdates back to the registry (so transport-level offline transitions
// surface on the next /federation load).
func (p *hubFederationProvider) FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error) {
	if p.server.hub == nil {
		return &federation.FanOutResult{}, nil
	}
	spokes := p.Spokes()
	res, err := p.fanOutClient().Execute(ctx, spokes, req)
	if err != nil || res == nil {
		return res, err
	}
	if len(res.StatusUpdates) > 0 {
		p.server.hub.mu.Lock()
		for nodeID, st := range res.StatusUpdates {
			_ = p.server.hub.registry.SetStatus(nodeID, st)
		}
		p.server.persistFederationLocked()
		p.server.hub.mu.Unlock()
	}
	return res, nil
}

// Compile-time assertion that hubFederationProvider satisfies the resolver
// contract.
var _ ddxgraphql.FederationProvider = (*hubFederationProvider)(nil)

package server

// land_coordinator.go — per-project land coordinator goroutine.
//
// The land coordinator is the server-side implementation of the human-PR
// landing model. For each project, a single goroutine owns all writes to the
// project's target refs. Workers (goroutines running ExecuteBead) submit
// their completed results to the coordinator via a channel; the coordinator
// drains the channel in FIFO order and invokes agent.Land() for each
// submission.
//
// Contract:
//   - Exactly one coordinator goroutine per projectRoot. Lazily created on
//     first submission and cached in WorkerManager so subsequent runWorker
//     invocations reuse it.
//   - Submissions block the submitter until the coordinator returns a
//     LandResult. This is a channel-based future/promise pattern.
//   - The coordinator does NOT share state with other projects'
//     coordinators. Full isolation per projectRoot.
//   - The coordinator goroutine survives individual runWorker invocations.
//     It exits only when the WorkerManager is stopped (not implemented
//     here — coordinators live for the lifetime of the server process).
//
// Why: see ddx-8746d8a6 / ddx-e14efc58 / ddx-6aa50e57.

import (
	"fmt"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
)

// LandOutcomeSummary is one entry in the coordinator's last-N submissions log.
type LandOutcomeSummary struct {
	TS          time.Time `json:"ts"`
	BeadID      string    `json:"bead_id,omitempty"`
	AttemptID   string    `json:"attempt_id,omitempty"`
	Outcome     string    `json:"outcome"` // landed | preserved | failed
	DurationMS  int64     `json:"duration_ms"`
	CommitCount int       `json:"commit_count"` // worker's contribution size (BaseRev..ResultRev)
}

// CoordinatorMetrics holds all in-memory metrics for one LandCoordinator.
// All fields are protected by the owning LandCoordinator's metricsMu.
type CoordinatorMetrics struct {
	// Outcome counters
	Landed     int64 `json:"landed"`
	Preserved  int64 `json:"preserved"`
	Failed     int64 `json:"failed"`
	PushFailed int64 `json:"push_failed"`
	// Total duration in milliseconds (sum, for computing avg)
	TotalDurationMS int64 `json:"total_duration_ms"`
	// Total contribution commits across all submissions (sum of
	// BaseRev..ResultRev counts)
	TotalCommits int64 `json:"total_commits"`
	// PreservedRatio is (preserved+failed) / total over the last window
	PreservedRatio float64 `json:"preserved_ratio"`
	// LastSubmissions holds up to the last 10 outcomes
	LastSubmissions []LandOutcomeSummary `json:"last_submissions,omitempty"`
}

// LandSubmission is one worker-to-coordinator submission. Submissions block
// on replyCh until the coordinator has processed them and pushed the
// LandResult back.
type LandSubmission struct {
	Request agent.LandRequest
	replyCh chan landReply
}

type landReply struct {
	result *agent.LandResult
	err    error
}

// LandCoordinator owns a single goroutine that serializes agent.Land() calls
// for one projectRoot. Create via newLandCoordinator; lifetime is tied to
// the owning WorkerManager.
type LandCoordinator struct {
	projectRoot string
	gitOps      agent.LandingGitOps
	queue       chan *LandSubmission
	done        chan struct{}

	metricsMu sync.Mutex
	metrics   CoordinatorMetrics
}

// NewLocalLandCoordinator returns a process-local LandCoordinator for use
// by CLI commands such as `ddx work` / `legacy agent execute-loop`. It has the same
// single-writer semantics as the server-hosted coordinator but its lifetime
// is tied to the CLI invocation. Stop() should be called on function exit.
func NewLocalLandCoordinator(projectRoot string, gitOps agent.LandingGitOps) *LandCoordinator {
	return newLandCoordinator(projectRoot, gitOps)
}

func newLandCoordinator(projectRoot string, gitOps agent.LandingGitOps) *LandCoordinator {
	if gitOps == nil {
		gitOps = agent.RealLandingGitOps{}
	}
	c := &LandCoordinator{
		projectRoot: projectRoot,
		gitOps:      gitOps,
		// Buffered so a single-worker happy path does not block on a
		// channel handoff. Additional submissions queue up naturally.
		queue: make(chan *LandSubmission, 32),
		done:  make(chan struct{}),
	}
	go c.run()
	return c
}

// Submit sends req to the coordinator and blocks until the LandResult is
// available. Safe to call concurrently from any number of goroutines — the
// coordinator processes submissions in FIFO order.
func (c *LandCoordinator) Submit(req agent.LandRequest) (*agent.LandResult, error) {
	sub := &LandSubmission{
		Request: req,
		replyCh: make(chan landReply, 1),
	}
	select {
	case c.queue <- sub:
	case <-c.done:
		return nil, fmt.Errorf("land coordinator for %s has stopped", c.projectRoot)
	}
	reply := <-sub.replyCh
	return reply.result, reply.err
}

// Stop closes the submission queue and signals the coordinator goroutine to
// exit after draining any in-flight submissions. Intended for test cleanup
// and process shutdown; not currently called from the server HTTP path.
func (c *LandCoordinator) Stop() {
	select {
	case <-c.done:
		return
	default:
	}
	close(c.done)
	close(c.queue)
}

// run is the coordinator goroutine. It drains queue in FIFO order, calling
// agent.Land() for each submission. One submission at a time — this is the
// single-writer guarantee for target-ref writes on projectRoot.
func (c *LandCoordinator) run() {
	for sub := range c.queue {
		start := time.Now()
		result, err := agent.Land(c.projectRoot, sub.Request, c.gitOps)
		elapsed := time.Since(start)
		c.recordMetrics(sub.Request, result, err, elapsed)
		sub.replyCh <- landReply{result: result, err: err}
	}
}

// recordMetrics updates the in-memory metrics after a Land() call.
func (c *LandCoordinator) recordMetrics(req agent.LandRequest, result *agent.LandResult, err error, elapsed time.Duration) {
	const maxLastSubmissions = 10

	outcome := "failed"
	commitCount := 0
	if err == nil && result != nil {
		switch result.Status {
		case "landed":
			outcome = "landed"
			commitCount = result.MergedCommitCount
		case "preserved":
			outcome = "preserved"
			commitCount = result.MergedCommitCount
		default:
			outcome = "failed"
		}
	}

	elapsedMS := elapsed.Milliseconds()

	c.metricsMu.Lock()
	defer c.metricsMu.Unlock()

	switch outcome {
	case "landed":
		c.metrics.Landed++
	case "preserved":
		c.metrics.Preserved++
	case "failed":
		c.metrics.Failed++
	}
	c.metrics.TotalDurationMS += elapsedMS
	c.metrics.TotalCommits += int64(commitCount)

	total := c.metrics.Landed + c.metrics.Preserved + c.metrics.Failed
	if total > 0 {
		c.metrics.PreservedRatio = float64(c.metrics.Preserved+c.metrics.Failed) / float64(total)
	}

	entry := LandOutcomeSummary{
		TS:          time.Now().UTC(),
		BeadID:      req.BeadID,
		AttemptID:   req.AttemptID,
		Outcome:     outcome,
		DurationMS:  elapsedMS,
		CommitCount: commitCount,
	}
	c.metrics.LastSubmissions = append(c.metrics.LastSubmissions, entry)
	if len(c.metrics.LastSubmissions) > maxLastSubmissions {
		c.metrics.LastSubmissions = c.metrics.LastSubmissions[len(c.metrics.LastSubmissions)-maxLastSubmissions:]
	}
}

// Metrics returns a snapshot of the coordinator's current metrics.
// Safe to call concurrently.
func (c *LandCoordinator) Metrics() CoordinatorMetrics {
	c.metricsMu.Lock()
	defer c.metricsMu.Unlock()
	// Copy slice to avoid data races on the caller side
	m := c.metrics
	if len(c.metrics.LastSubmissions) > 0 {
		m.LastSubmissions = make([]LandOutcomeSummary, len(c.metrics.LastSubmissions))
		copy(m.LastSubmissions, c.metrics.LastSubmissions)
	}
	return m
}

// coordinatorRegistry is the WorkerManager's per-project coordinator cache.
// It is lazily populated on first Submit call for a given projectRoot and
// persists for the lifetime of the process.
type coordinatorRegistry struct {
	mu           sync.Mutex
	coordinators map[string]*LandCoordinator
	// gitOpsOverride, when non-nil, is injected into each newly created
	// coordinator instead of RealLandingGitOps. Tests use this.
	gitOpsOverride agent.LandingGitOps
}

func newCoordinatorRegistry() *coordinatorRegistry {
	return &coordinatorRegistry{
		coordinators: map[string]*LandCoordinator{},
	}
}

// Get returns the coordinator for projectRoot, creating one on first access.
// Safe to call concurrently.
func (r *coordinatorRegistry) Get(projectRoot string) *LandCoordinator {
	r.mu.Lock()
	defer r.mu.Unlock()
	if c, ok := r.coordinators[projectRoot]; ok {
		return c
	}
	c := newLandCoordinator(projectRoot, r.gitOpsOverride)
	r.coordinators[projectRoot] = c
	return c
}

// StopAll stops every coordinator in the registry. For test cleanup.
func (r *coordinatorRegistry) StopAll() {
	r.mu.Lock()
	defer r.mu.Unlock()
	for _, c := range r.coordinators {
		c.Stop()
	}

package federation

import (
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/update"
)

// HandshakeResult is the outcome of validating a spoke's version handshake
// against the hub's own version + schema version.
type HandshakeResult struct {
	// Accept reports whether the registration should be accepted at all.
	Accept bool
	// Status is the SpokeStatus to record on accepted registrations:
	// StatusRegistered when fully compatible (heartbeat will move it to
	// StatusActive), or StatusDegraded when accepted-but-newer.
	Status SpokeStatus
	// Reason is a short, machine-readable code for the outcome — used as the
	// rejection reason on 4xx and as a degraded-status reason on accept.
	// Stable enum: "ok", "degraded_newer_minor",
	// "schema_mismatch", "ddx_major_mismatch", "missing_ddx_version",
	// "missing_schema_version", "invalid_ddx_version".
	Reason string
}

// Handshake validates a spoke's version handshake.
//
//   - schema_version must match the hub's schema version exactly. Anything
//     else is rejected ("schema_mismatch").
//   - ddx_version must parse as semver. Major version must match the hub.
//     A higher minor or patch on the spoke side accepts as StatusDegraded
//     ("degraded_newer_minor"). Equal-or-lower minors/patches accept as
//     StatusRegistered ("ok"). Mismatched majors are rejected
//     ("ddx_major_mismatch").
//
// Empty / unparseable inputs are rejected with descriptive reasons.
func Handshake(hubDDxVersion, hubSchemaVersion, spokeDDxVersion, spokeSchemaVersion string) HandshakeResult {
	if strings.TrimSpace(spokeSchemaVersion) == "" {
		return HandshakeResult{Reason: "missing_schema_version"}
	}
	if spokeSchemaVersion != hubSchemaVersion {
		return HandshakeResult{Reason: "schema_mismatch"}
	}
	if strings.TrimSpace(spokeDDxVersion) == "" {
		return HandshakeResult{Reason: "missing_ddx_version"}
	}
	hubParts, err := update.ParseVersion(hubDDxVersion)
	if err != nil {
		return HandshakeResult{Reason: fmt.Sprintf("invalid_hub_ddx_version:%v", err)}
	}
	spokeParts, err := update.ParseVersion(spokeDDxVersion)
	if err != nil {
		return HandshakeResult{Reason: "invalid_ddx_version"}
	}
	if spokeParts[0] != hubParts[0] {
		return HandshakeResult{Reason: "ddx_major_mismatch"}
	}
	// Same major, compare minor.patch. Any newer minor or patch on the spoke
	// side is "compatible-but-newer" → degraded.
	newer := spokeParts[1] > hubParts[1] ||
		(spokeParts[1] == hubParts[1] && spokeParts[2] > hubParts[2])
	if newer {
		return HandshakeResult{Accept: true, Status: StatusDegraded, Reason: "degraded_newer_minor"}
	}
	return HandshakeResult{Accept: true, Status: StatusRegistered, Reason: "ok"}
}

